#include "fvMesh.H"

void meshInfo(const fvMesh& mesh)
{
    // Access basic mesh dimensions
    Info<< "Number of points: " << mesh.nPoints() << endl;
    Info<< "Number of faces: " << mesh.nFaces() << endl;
    Info<< "Number of cells: " << mesh.nCells() << endl;

    // Access mesh points
    const pointField& points = mesh.points();
    Info<< "First point: " << points[0] << endl;

    // Access faces
    const faceList& faces = mesh.faces();
    Info<< "First face has " << faces[0].size() << " points" << endl;
}

#include "fvMesh.H"

void addressingInfo(const fvMesh& mesh)
{
    // Face owner and neighbor lists
    const labelList& owner = mesh.faceOwner();
    const labelList& neighbour = mesh.faceNeighbour();

    // Count internal faces (have neighbors)
    label nInternalFaces = 0;
    forAll(neighbour, facei)
    {
        if (neighbour[facei] != -1)
        {
            nInternalFaces++;
            // This is an internal face
            label cellOwner = owner[facei];
            label cellNeighbour = neighbour[facei];
        }
    }

    Info<< "Internal faces: " << nInternalFaces 
        << " Boundary faces: " << mesh.nFaces() - nInternalFaces << endl;}

#include "fvMesh.H"

void boundaryInfo(const fvMesh& mesh)
{
    // Iterate over boundary patches
    forAll(mesh.boundaryMesh(), patchi)
    {
        const polyPatch& patch = mesh.boundaryMesh()[patchi];

        Info<< "Patch " << patch.name() 
            << " type: " << patch.type()
            << " nFaces: " << patch.size() << endl;

        // Access patch-specific data
        if (isA<wallPolyPatch>(patch))
        {
            Info<< "  This is a wall boundary" << endl;
        }
        else if (isA<cyclicPolyPatch>(patch))
        {
            Info<< "  This is a cyclic boundary" << endl;
        }
    }
}

#include "fvMesh.H"

void zonesInfo(const fvMesh& mesh)
{
    // Cell zones
    const cellZoneList& cellZones = mesh.cellZones();
    Info<< "Cell zones: " << cellZones.size() << endl;

    forAll(cellZones, zonei)
    {
        const cellZone& zone = cellZones[zonei];
        Info<< "  Zone " << zone.name() << " has " << zone.size() << " cells" << endl;
    }

    // Face zones
    const faceZoneList& faceZones = mesh.faceZones();
    Info<< "Face zones: " << faceZones.size() << endl;

    // Point zones
    const pointZoneList& pointZones = mesh.pointZones();
    Info<< "Point zones: " << pointZones.size() << endl;
}

#include "fvMesh.H"
#include "volFields.H"
#include "surfaceFields.H"

void meshDataInfo(const fvMesh& mesh)
{
    // Cell volumes (lazy evaluation)
    const scalarField& V = mesh.V();
    Info<< "Total volume: " << sum(V) << endl;
    Info<< "Min cell volume: " << gMin(V) 
        << " Max cell volume: " << gMax(V) << endl;

    // Face areas
    const vectorField& Sf = mesh.Sf();
    const scalarField& magSf = mesh.magSf();

    Info<< "Total face area: " << sum(magSf) << endl;

    // Face centres
    const vectorField& Cf = mesh.Cf();
    Info<< "First face centre: " << Cf[0] << endl;
}
